/* Cosine Law */

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int main()
{
    float a, b, c, theta;

    printf ("Enter length of one side: ");
    scanf ("%f", &a);
    printf ("Enter length of another side: ");
    scanf ("%f", &b);
    printf ("The angle between the two(in radian): ");
    scanf ("%f", &theta);

    c = sqrt(pow(a,2)+pow(b,2)-2*a*b*cos(theta));

    printf ("\n");
    printf ("The third side length is: %f\n", c);
    printf ("\n");

    system ("pause");
    return 0;

}

/* Reverse of a number */

#include <stdio.h>
#include <stdlib.h>

int main()
{
    int a, k, b, c, x, y;

    printf("Enter a 3 digit number: ");
    scanf("%d", &x);

    a = x/100;
    k = x%100;
    b = k-k%10;
    c = k%10;

    y = 100*c + b + a;

    printf("\nThe inverse of %.3d is: %.3d\n\n", x, y);

    system("pause");
    return 0;
}

/* Money */

#include <stdio.h>
#include <stdlib.h>

int main()
{
    int x, quat, dim, nick, pen;

    printf("Enter and amount: ");
    scanf("%d", &x);

    quat = x/25;
    dim = (x%25)/10;
    nick = (x-quat*25-dim*10)/5;
    pen = x-quat*25-dim*10-nick*5;

    printf("\n");
    printf("%d quarter(s), %d dime(s), %d nickel(s), %d penny(ies)\n", quat, dim, nick, pen);
    printf("\n");

    system("pause");
    return 0;
}

/* Quadratic Equation */

#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int main()
{
    float a, b, c, x_1, x_2, x_3, x_4;

    printf ("\nax^2 + bx + c =0\n\n");

    printf ("\ta= ");
    scanf ("%f", &a);
    printf ("\tb= ");
    scanf ("%f", &b);
    printf ("\tc= ");
    scanf ("%f", &c);

    x_1 = (-b + sqrt(b*b - 4*a*c))/(2*a);
    x_2 = (-b - sqrt(b*b - 4*a*c))/(2*a);
    x_3 = -b/(2*a);
    x_4 = sqrt((4*a*c - b*b)/(4*a*a));

    if (a == 0 && b == 0 && c != 0)
       printf ("\n'c' must be 0.\n\n");
    else if (a == 0 && b == 0 && c == 0)
       printf ("\nAll zero...stop fooling around...\n\n");
    else if (a == 0)
       printf ("\nThe solution of the equation is %.2f.\n\n", (-c/b));
    else if ((b*b - 4*a*c) > 0)
       printf ("\nThe solutions of the equation are %.2f, and %.2f.\n\n", x_1, x_2);
    else if ((b*b - 4*a*c) == 0)
       printf ("\nThe only solution is %.2f.\n\n", x_1);
    else
       printf ("\nThe solutions are (%.2f + %.3fi), and (%.2f - %.3fi).\n\n", x_3, x_4, x_3, x_4);

    system ("pause");
    main();
}

