    printf("Enter a base between 2-9: ");
    scanf("%d", &base);

    deci_ori = deci;
    base_ori = base;

    for(;deci>0;p++)
       deci/=base;

    deci = deci_ori;

    printf("%d in base %d is ", deci, base);

    for(;p>0;p--) {
       base = base_ori;
       for(np=1;np<p;np++)
