void factor(long long int n)
{
	  long long int i=2, j=n, k=0;

	  printf("\n\n   It can be factored as: \n\n\n     ");

     for (;i<n;i++,j=n) {
			while (j%i==0) {
          	j/=i;
				k++;
   		}

