    else if ((a[0]=='O' && a[1]=='O' && a[6]==' ') || (a[7]=='O' && a[8]=='O' && a[6]==' ') || (a[4]=='O' && a[2]=='O' && a[6]==' ')) return 6;  // Bottom Left
