#define SIZE 100

int binary_search(int array[], int);

int main()
{
	 int array[SIZE], i, num;

	 printf("\n  ");
	 for(i=0;i<SIZE;i++) {
		 array[i] = i*2+i/2;
		 printf("%5d", array[i]);
		 if ((i+1)%10==0) printf("\n  ");
	 }

	 printf("\n\n\tWhat number are you looking for? ");
	 scanf("%d", &num);

	 if (binary_search(array, num) == -1)
		 printf("\n\tNo such number in the list!!");
	 else
	    printf("\n\tValue %d is stored in array[%d]", num, binary_search(array, num));

    getch();
    system("cls");
    main();
    return 0;
}

int binary_search(int array[], int num)
{
	 int low=0, high=SIZE-1, mid;

	 while(low!=high-1) {
		 mid=(low+high)/2;
		 if(array[mid]>num) high=mid;
		 else if (array[mid]<num) low=mid;
		 else return mid;
	 }
	 return -1;
}

/* Largest sum of row or column */

#include<stdio.h>
#include<time.h>
#define row 16
#define col 16

int largest(int array[row][col]);
void result(int, int, int);

int main()
{
	 int array[row][col], i, j;

	 srand((unsigned) time(NULL));

	 printf("\n\n      |");
	 for(i=1;i<=col;i++)
		 printf("%4d", i);

	 printf("\n   ");
	 for(i=0;i<(col+1)*4;i++) {
		 if (i==3) printf("+");
		 else printf("-");
	 }

	 for(i=0;i<row;i++) {
		 printf("\n   %2d |", i+1);
		 for(j=0;j<col;j++) {
			 array[i][j]=rand()%100+1;
			 printf("%4d", array[i][j]);
		 }
	 }

	 largest(array);
}

int largest(int array[row][col])
{
	 int sum, larger_sum=0, i, j, k, cor;

	 //sum row
	 for(i=0;i<row;i++) {
		 sum=0;
		 for(j=0;j<col;j++)
		    sum += array[i][j];
		 if (sum>larger_sum) {
		    larger_sum=sum;
		    k=i+1;
		    cor=1;
		 }
	 }

	 //sum col
	 for(i=0;i<col;i++) {
		 sum=0;
		 for(j=0;j<row;j++)
		    sum += array[j][i];
		 if (sum>larger_sum) {
		 	 larger_sum=sum;
		 	 k=i+1;
		 	 cor=2;
		 }
	 }

	 result(larger_sum, k, cor);
}

void result(int sum, int k, int cor)
{
    printf("\n\n\n   The largerst sum is ");
	 if(cor==1) printf("%d in row %d", sum, k);
	 else printf("%d in col %d", sum, k);

	 getch();
	 system("cls");
	 main();
}

