int a[SIZE][SIZE];

int main()
{
    int i, j, over=1;
    char choice;

    hide_cursor();

    for (i=0;i<SIZE;i++)
        for (j=0;j<SIZE;j++)
            a[i][j]=SIZE*i+j+1;

    do {

       print();

       switch (choice = getch()) {
          case '1': case '2': case '3': case '4':
             exchange(choice); break;
          case '5':
             over=0; break;
       }

    } while(over);

    return 0;
}

void exchange(char choice)
{
     int i, j, temp[SIZE][SIZE];

     for (i=0;i<SIZE;i++)
         for (j=0;j<SIZE;j++)
             temp[i][j]=a[i][j];

     for (i=0;i<SIZE;i++)
         for (j=0;j<SIZE;j++) {
             if (choice == '1') a[i][j]=temp[i][SIZE-j-1];        // tl_tr
             if (choice == '2') a[i][j]=temp[SIZE-i-1][SIZE-j-1]; // tl_br
             if (choice == '3') a[i][j]=temp[SIZE-i-1][j];        // tl_bl
             if (choice == '4') a[i][j]=temp[j][i];               // tr_bl
         }
}


