int first(char *a, char *b)
{
    int i, j, ct;
    char *aptr=a, *bptr=b;

    for (i=0; i<mystrlen(a); i++) {
        *bptr=*b;
        for (j=0, ct=0; j<mystrlen(b); j++) {
            if (*(aptr+i+j) == *(bptr+j)) ct++;
            else break;
        }
        if (ct == mystrlen(b)) break;
    }

    if (i == mystrlen(a)) return -1;

    return i;
}

