void convert(const char *from, char *to)
{
     int i=0, j=i;

     while (*(from+i) != '\0') {
        if (*(from+i) >= 'A' && *(from+i) <='Z') {
           *(to+i+j++)=' ';
           *(to+i+j)=*(from+i)+32;
        }
        else *(to+i+j)=*(from+i);

        i++;
     }

     *(to+i+j)=0;

     return;
}

