void hide_cursor()
{
     HANDLE hcon = GetStdHandle(STD_OUTPUT_HANDLE);
     CONSOLE_CURSOR_INFO cci;
     cci.bVisible = FALSE;
     cci.dwSize = 25;
     SetConsoleCursorInfo(hcon,&cci);
}

